{
  "domain_analysis": {
    "business_context": "Order cancellation in a logistics/courier domain. A user-initiated cancellation must respect the physical reality of package fulfillment — once a courier has possession of goods or delivery is underway, cancellation has materially different consequences than cancelling a newly-placed order. The spec is dangerously vague: it says nothing about which order states permit cancellation, what 'cancel' means financially, or who qualifies as 'the user.'",
    "bounded_context": "Order Management / Order Lifecycle",
    "ubiquitous_language": [
      { "term": "Order", "definition": "A request by a sender to have a package picked up from an origin and delivered to a destination." },
      { "term": "Order Status", "definition": "The current lifecycle state of an order (e.g., Placed, Confirmed, Assigned, PickedUp, InTransit, OutForDelivery, Delivered, Cancelled, Failed)." },
      { "term": "Cancellation", "definition": "A user-initiated request to terminate an order before its successful completion. May result in a full refund, partial refund, or no refund depending on order status at time of request." },
      { "term": "Cancellation Window", "definition": "The set of order statuses during which cancellation is permitted without operational penalty." },
      { "term": "Sender", "definition": "The party who placed and is paying for the order. The primary actor for cancellation." },
      { "term": "Recipient", "definition": "The party receiving the delivery. Typically NOT authorized to cancel, only to refuse delivery." },
      { "term": "Courier", "definition": "The assigned driver/rider fulfilling the delivery." },
      { "term": "Cancellation Fee", "definition": "A charge applied when cancellation occurs after the courier has already been dispatched or has begun work on the order." },
      { "term": "Refund", "definition": "The return of payment to the sender, full or partial, triggered by a successful cancellation." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "Only the sender (order creator) may cancel an order. Recipients and other parties cannot initiate cancellation.",
      "invariant": true,
      "invariant_justification": "Allowing non-owners to cancel orders would corrupt order integrity and enable abuse. This is an authorization constraint tied to data ownership.",
      "testable_assertion": "Given a user who is not the sender of an order, when they attempt to cancel it, the system must reject the request with an authorization error."
    },
    {
      "id": "BR-2",
      "rule": "An order may only be cancelled if its current status is within the cancellation window: Placed, Confirmed, or Assigned.",
      "invariant": false,
      "invariant_justification": "The specific set of cancellable statuses is a business policy decision. A VP could expand or narrow this window (e.g., allow cancellation during PickedUp with a higher fee).",
      "testable_assertion": "Given an order in status PickedUp, InTransit, OutForDelivery, or Delivered, when the sender requests cancellation, the system must reject the request and explain which statuses allow cancellation."
    },
    {
      "id": "BR-3",
      "rule": "An order that has already been cancelled or has reached a terminal state (Delivered, Failed) cannot be cancelled again.",
      "invariant": true,
      "invariant_justification": "Cancelling a terminal-state order violates state machine integrity. A delivered package cannot be un-delivered. Double-cancellation could trigger duplicate refunds, corrupting financial records.",
      "testable_assertion": "Given an order in status Cancelled or Delivered, when a cancellation request is made, the system must reject it as an invalid state transition."
    },
    {
      "id": "BR-4",
      "rule": "Cancellation must be an atomic operation: the order status transitions to Cancelled, and any assigned courier is released, within a single transaction. No order may exist in an intermediate 'cancelling' state visible to other actors.",
      "invariant": true,
      "invariant_justification": "A partially-cancelled order — status changed but courier still assigned — creates an inconsistent state where a courier could deliver a cancelled order. This is a data consistency invariant.",
      "testable_assertion": "Given an order in status Assigned with a courier, when cancelled, the order status must be Cancelled AND the courier assignment must be released atomically. No read of the order between these two changes should be possible."
    },
    {
      "id": "BR-5",
      "rule": "Cancellation of an order in status Placed or Confirmed triggers a full refund. Cancellation of an order in status Assigned (courier dispatched but not yet picked up) triggers a refund minus a cancellation fee.",
      "invariant": false,
      "invariant_justification": "Refund amounts and fee structures are business policy, adjustable by finance or product teams.",
      "testable_assertion": "Given an order in status Placed, when cancelled, a refund equal to 100% of the order amount is issued. Given an order in status Assigned, when cancelled, a refund equal to (order amount - cancellation fee) is issued."
    },
    {
      "id": "BR-6",
      "rule": "Every cancellation must record: who cancelled, when, the order status at time of cancellation, and the reason (if provided). This audit trail is immutable.",
      "invariant": true,
      "invariant_justification": "Audit trails for financial events are required for dispute resolution, compliance, and reconciliation. An unaudited cancellation corrupts the financial record.",
      "testable_assertion": "Given any successful cancellation, the system must persist a cancellation record containing: user_id, timestamp, previous_order_status, and optional reason. This record must not be deletable or editable."
    },
    {
      "id": "BR-7",
      "rule": "A cancellation event must notify all affected parties: the sender (confirmation), the courier (if assigned), and any downstream systems (payment, analytics).",
      "invariant": false,
      "invariant_justification": "Notification channels and targets are operational policy, not state integrity. Missing a notification is bad but does not corrupt the domain.",
      "testable_assertion": "Given a successful cancellation of an Assigned order, the system must emit notifications to both the sender and the assigned courier."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "An authenticated sender with an order in status Placed",
      "when": "The sender requests cancellation of that order",
      "then": "The order status transitions to Cancelled, a full refund is initiated, a cancellation audit record is created, and the sender receives a cancellation confirmation"
    },
    {
      "id": "AC-2",
      "given": "An authenticated sender with an order in status Confirmed",
      "when": "The sender requests cancellation of that order",
      "then": "The order status transitions to Cancelled, a full refund is initiated, a cancellation audit record is created, and the sender receives a cancellation confirmation"
    },
    {
      "id": "AC-3",
      "given": "An authenticated sender with an order in status Assigned (courier dispatched, package not yet picked up)",
      "when": "The sender requests cancellation of that order",
      "then": "The order status transitions to Cancelled, the courier assignment is released, a partial refund (order amount minus cancellation fee) is initiated, the courier is notified, and a cancellation audit record is created"
    },
    {
      "id": "AC-4",
      "given": "An authenticated sender with an order in status PickedUp, InTransit, OutForDelivery, or Delivered",
      "when": "The sender requests cancellation",
      "then": "The system rejects the request with a clear error message stating the order is no longer eligible for cancellation and indicating the current status"
    },
    {
      "id": "AC-5",
      "given": "An authenticated sender with an order already in status Cancelled",
      "when": "The sender requests cancellation again",
      "then": "The system rejects the request as a no-op, returns a message that the order is already cancelled, and does NOT issue a duplicate refund"
    },
    {
      "id": "AC-6",
      "given": "An authenticated user who is NOT the sender of the order",
      "when": "They attempt to cancel the order",
      "then": "The system rejects the request with an authorization error and does not modify the order"
    },
    {
      "id": "AC-7",
      "given": "Two simultaneous cancellation requests for the same order in status Placed",
      "when": "Both requests are processed concurrently",
      "then": "Exactly one cancellation succeeds, exactly one refund is issued, and the second request receives an 'already cancelled' response. No duplicate refunds are created."
    },
    {
      "id": "AC-8",
      "given": "An order in status Assigned where the courier picks up the package at the exact moment of a cancellation request",
      "when": "Cancellation and pickup events race",
      "then": "Exactly one transition wins. If cancellation wins, the courier is notified to abort pickup. If pickup wins, the cancellation is rejected with a status-change error."
    },
    {
      "id": "AC-9",
      "given": "A successful cancellation of any order",
      "when": "The cancellation audit log is queried",
      "then": "The log contains: cancelling user ID, UTC timestamp, order ID, order status at the moment before cancellation, and optional user-provided reason"
    },
    {
      "id": "AC-10",
      "given": "A cancellation request where the downstream refund service is unavailable",
      "when": "The cancellation is processed",
      "then": "The order status transitions to Cancelled (to prevent further fulfillment), the refund is queued for retry, and the sender is informed that the refund is processing"
    }
  ],

  "edge_cases": [
    {
      "scenario": "Concurrent cancellation and courier pickup race condition",
      "expected_behavior": "The system must use optimistic locking or equivalent concurrency control on order status. Exactly one state transition wins. If cancellation wins, courier is notified to abort. If pickup wins, cancellation is rejected. No order may simultaneously be Cancelled and PickedUp."
    },
    {
      "scenario": "Double-cancel request (user clicks cancel button twice rapidly)",
      "expected_behavior": "Idempotent handling: the first request transitions the order to Cancelled and issues one refund. The second request returns success (already cancelled) but does NOT issue a second refund."
    },
    {
      "scenario": "Cancellation when payment has not yet been captured (e.g., authorized but not settled)",
      "expected_behavior": "The system should void the authorization rather than issuing a refund. The financial operation differs but the domain event is still 'Order Cancelled.'"
    },
    {
      "scenario": "Cancellation of an order with multiple parcels or legs",
      "expected_behavior": "Cancellation must apply to the entire order atomically. Partial cancellation (cancelling one parcel) is a different feature and must not be conflated with order cancellation."
    },
    {
      "scenario": "Cancellation immediately after order placement, before status propagates to all systems",
      "expected_behavior": "The order status is the source of truth. If the order record exists and is in status Placed, cancellation is valid regardless of whether downstream systems have processed the creation event yet."
    },
    {
      "scenario": "Refund service is down at time of cancellation",
      "expected_behavior": "The order must still transition to Cancelled to prevent fulfillment. The refund must be queued and retried. Cancellation must not be blocked by refund service availability — preventing a courier from making a wasted trip is higher priority."
    },
    {
      "scenario": "Sender's account is deactivated or suspended between order placement and cancellation attempt",
      "expected_behavior": "A suspended sender should still be able to cancel their own orders. Blocking cancellation for suspended accounts would force the company to fulfill an order the user doesn't want, wasting courier resources."
    },
    {
      "scenario": "Order was placed via API integration by a third-party platform (e.g., e-commerce plugin)",
      "expected_behavior": "The cancellation must notify the originating platform via webhook or callback. The third-party platform is the 'sender' for authorization purposes, not the end consumer."
    }
  ],

  "business_impact": {
    "financial": "Cancellation directly impacts revenue (lost delivery fees), refund processing costs, and potential cancellation fee revenue. Poor implementation risks duplicate refunds (direct financial loss) or blocked cancellations (wasted courier costs, customer disputes, chargebacks). Correct cancellation-fee logic is a revenue protection mechanism.",
    "operational": "Timely cancellation frees courier capacity for other deliveries. Late or failed cancellation notifications to couriers result in wasted trips, fuel costs, and reduced fleet utilization. The atomicity requirement prevents 'ghost assignments' where couriers work on cancelled orders.",
    "user": "Cancellation is a trust-building feature. Users who can easily cancel orders feel safe placing them. Friction in cancellation (unclear errors, slow processing, missing refunds) directly drives churn. Clear communication about the cancellation window sets expectations and reduces support tickets.",
    "risk": "Primary risks: (1) duplicate refund financial exposure from race conditions, (2) courier safety if cancellation notification fails mid-pickup, (3) compliance risk if audit trail is incomplete for chargeback disputes, (4) reputational risk if cancellation appears to succeed but fulfillment continues.",
    "stakeholders_affected": [
      { "group": "Senders (customers)", "impact": "Gain ability to cancel orders and recover funds. Experience depends on clarity of cancellation window, speed of refund, and quality of confirmation messaging." },
      { "group": "Couriers", "impact": "Must receive timely cancellation notifications to avoid wasted trips. Late notification after pickup creates a return-to-origin burden." },
      { "group": "Finance/Accounting", "impact": "Must reconcile cancellations, refunds, and cancellation fees. Requires reliable audit trail for dispute resolution and financial reporting." },
      { "group": "Customer Support", "impact": "Will handle edge cases where automated cancellation is rejected (e.g., order past cancellation window). Needs clear escalation path for manual cancellations." },
      { "group": "Third-party platform partners", "impact": "Must receive cancellation webhooks to keep their order state in sync. Missed notifications cause state drift between systems." }
    ]
  },

  "confidence": {
    "level": 42,
    "reasoning": "The spec is a single sentence with no definition of order lifecycle states, cancellation window, refund policy, fee structure, authorization model, or notification requirements. Every business rule above is inferred from standard logistics domain knowledge, not from an actual specification. The cancellation fee amount is completely unspecified. Whether recipients or support agents can cancel is unstated. Multi-parcel order handling is unaddressed. This analysis is a best-effort interpretation of an extremely vague requirement.",
    "high_confidence_areas": [
      "Only the order owner should be able to cancel (fundamental authorization principle)",
      "Terminal-state orders cannot be cancelled (physical reality: you cannot un-deliver a package)",
      "Cancellation must be atomic to prevent ghost assignments",
      "Audit trail is required for any financial state change"
    ],
    "low_confidence_areas": [
      "Exact set of statuses in the cancellation window — depends on this system's specific order lifecycle",
      "Refund policy and cancellation fee amounts — pure business policy, not specified",
      "Whether customer support agents can cancel on behalf of users",
      "Whether partial cancellation of multi-parcel orders is in scope",
      "How third-party/API-originated orders are handled for cancellation authorization"
    ],
    "assumptions": [
      "The system has an order lifecycle with at minimum: Placed, Confirmed, Assigned, PickedUp, InTransit, Delivered, Cancelled states",
      "Payment is captured at or before order confirmation",
      "A cancellation fee exists for orders where a courier has already been assigned",
      "The sender is the sole party authorized to cancel (no support agent override in this feature scope)",
      "Cancellation applies to the entire order, not individual items or parcels"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec does not define which order statuses permit cancellation. Is cancellation allowed after courier pickup but before delivery? The business must define the exact cancellation window, as it has direct financial and operational consequences.",
      "affected_stakeholders": ["Senders", "Couriers", "Finance"],
      "options": [
        "A: Allow cancellation only before courier pickup (Placed, Confirmed, Assigned)",
        "B: Allow cancellation up to InTransit with escalating fees",
        "C: Allow cancellation at any point before Delivered, with return-to-origin flow for physical possession cases"
      ],
      "recommendation": "Option A for MVP — it avoids the complexity of return-to-origin logistics. Options B and C can be phased in later."
    },
    {
      "type": "ambiguity",
      "description": "Who is 'the user'? The spec says 'users' but does not clarify if this means only the sender, or also the recipient, or customer support agents acting on behalf of users.",
      "affected_stakeholders": ["Senders", "Recipients", "Customer Support"],
      "options": [
        "A: Only the sender can cancel",
        "B: Sender and recipient can both cancel",
        "C: Sender can self-serve cancel; support agents can cancel on escalation with a different audit trail"
      ],
      "recommendation": "Option C — senders self-serve, support agents get a separate cancellation privilege. Recipients should only be able to refuse delivery, not cancel."
    },
    {
      "type": "missing_context",
      "description": "No refund policy is specified. What percentage is refunded at each stage? What is the cancellation fee amount or formula? This is a financial decision that cannot be inferred from the spec.",
      "affected_stakeholders": ["Senders", "Finance", "Product"],
      "options": [
        "A: Full refund always (simple, customer-friendly, but absorbs courier dispatch costs)",
        "B: Full refund before assignment, partial after (balances customer experience with cost recovery)",
        "C: Configurable fee schedule per order type or market"
      ],
      "recommendation": "Option B — standard industry practice. Exact fee amount needs Finance input."
    },
    {
      "type": "missing_context",
      "description": "The existing order lifecycle states are not specified. The acceptance criteria above assume a common logistics state machine, but the actual system may use different states or naming conventions.",
      "affected_stakeholders": ["Engineering", "Product"],
      "options": [
        "A: Adopt the states assumed in this analysis",
        "B: Map this analysis to the actual existing order states in the codebase"
      ],
      "recommendation": "Option B — engineering should provide the actual order state machine before implementation begins."
    }
  ],

  "rejection_reasons": []
}

